namespace SiteInspector.Models;

public class Site
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Name { get; set; } = string.Empty;
    public string Address { get; set; } = string.Empty;
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;
}

public class Inspection
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string SiteId { get; set; } = string.Empty;
    public DateTime InspectedAt { get; set; } = DateTime.UtcNow;
    public string InspectorName { get; set; } = string.Empty;
    public string Notes { get; set; } = string.Empty;
    public List<ChecklistItem> Checklist { get; set; } = new();
    public List<PhotoAttachment> Photos { get; set; } = new();
    public bool IsSynced { get; set; }
    public InspectionStatus Status { get; set; } = InspectionStatus.InProgress;
}

public class ChecklistItem
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public CheckResult Result { get; set; } = CheckResult.NotChecked;
    public string Notes { get; set; } = string.Empty;
}

public class PhotoAttachment
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string FileName { get; set; } = string.Empty;
    public string Base64Data { get; set; } = string.Empty;
    public string Caption { get; set; } = string.Empty;
    public DateTime TakenAt { get; set; } = DateTime.UtcNow;
}

public enum CheckResult
{
    NotChecked,
    Pass,
    Fail,
    NotApplicable
}

public enum InspectionStatus
{
    InProgress,
    Completed
}

namespace SiteInspector.Models;

public static class ChecklistTemplates
{
    public static List<ChecklistItem> GetStandardChecklist() => new()
    {
        // Fall Protection
        new() { Category = "Fall Protection", Description = "Guardrails installed on open edges" },
        new() { Category = "Fall Protection", Description = "Floor openings covered or guarded" },
        new() { Category = "Fall Protection", Description = "Safety nets in place where required" },
        new() { Category = "Fall Protection", Description = "Workers using harnesses at height" },

        // Scaffolding
        new() { Category = "Scaffolding", Description = "Scaffolding properly erected and braced" },
        new() { Category = "Scaffolding", Description = "Planking in good condition" },
        new() { Category = "Scaffolding", Description = "Access ladders provided" },
        new() { Category = "Scaffolding", Description = "Toe boards and guardrails in place" },

        // Electrical
        new() { Category = "Electrical", Description = "GFCI protection on temporary power" },
        new() { Category = "Electrical", Description = "Extension cords in good condition" },
        new() { Category = "Electrical", Description = "Electrical panels accessible and labeled" },
        new() { Category = "Electrical", Description = "Lockout/tagout procedures followed" },

        // Housekeeping
        new() { Category = "Housekeeping", Description = "Work areas clear of debris" },
        new() { Category = "Housekeeping", Description = "Materials properly stored" },
        new() { Category = "Housekeeping", Description = "Walkways and exits unobstructed" },
        new() { Category = "Housekeeping", Description = "Waste containers available and used" },

        // PPE
        new() { Category = "PPE", Description = "Hard hats worn in required areas" },
        new() { Category = "PPE", Description = "Safety glasses/goggles used" },
        new() { Category = "PPE", Description = "High-visibility vests worn" },
        new() { Category = "PPE", Description = "Appropriate footwear worn" },

        // Fire Safety
        new() { Category = "Fire Safety", Description = "Fire extinguishers accessible and charged" },
        new() { Category = "Fire Safety", Description = "Hot work permits in place" },
        new() { Category = "Fire Safety", Description = "Flammable materials properly stored" },
        new() { Category = "Fire Safety", Description = "Emergency evacuation routes posted" },

        // Excavation
        new() { Category = "Excavation", Description = "Trenches properly shored/sloped" },
        new() { Category = "Excavation", Description = "Spoil piles set back from edge" },
        new() { Category = "Excavation", Description = "Utilities located and marked" },
        new() { Category = "Excavation", Description = "Access/egress provided for deep excavations" },
    };
}

using SiteInspector.Models;

namespace SiteInspector.Services;

public interface IInspectionStore
{
    Task<List<Site>> GetSitesAsync();
    Task SaveSiteAsync(Site site);
    Task DeleteSiteAsync(string siteId);

    Task<List<Inspection>> GetInspectionsAsync(string siteId);
    Task<Inspection?> GetInspectionAsync(string inspectionId);
    Task SaveInspectionAsync(Inspection inspection);
    Task DeleteInspectionAsync(string inspectionId);

    Task<List<Inspection>> GetUnsyncedInspectionsAsync();
    Task MarkAsSyncedAsync(string inspectionId);
}

