using Blazored.LocalStorage;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class LocalInspectionStore : IInspectionStore
{
    private readonly ILocalStorageService _storage;
    private const string SitesKey = "sites";
    private const string InspectionsKeyPrefix = "inspections_";
    private const string AllInspectionIdsKey = "all_inspection_ids";

    public LocalInspectionStore(ILocalStorageService storage)
    {
        _storage = storage;
    }

    public async Task<List<Site>> GetSitesAsync()
    {
        return await _storage.GetItemAsync<List<Site>>(SitesKey) ?? new List<Site>();
    }

    public async Task SaveSiteAsync(Site site)
    {
        var sites = await GetSitesAsync();
        var existing = sites.FindIndex(s => s.Id == site.Id);
        if (existing >= 0)
            sites[existing] = site;
        else
            sites.Add(site);
        await _storage.SetItemAsync(SitesKey, sites);
    }

    public async Task DeleteSiteAsync(string siteId)
    {
        var sites = await GetSitesAsync();
        sites.RemoveAll(s => s.Id == siteId);
        await _storage.SetItemAsync(SitesKey, sites);
    }

    public async Task<List<Inspection>> GetInspectionsAsync(string siteId)
    {
        var ids = await GetAllInspectionIdsAsync();
        var inspections = new List<Inspection>();
        foreach (var id in ids)
        {
            var inspection = await GetInspectionAsync(id);
            if (inspection?.SiteId == siteId)
                inspections.Add(inspection);
        }
        return inspections.OrderByDescending(i => i.InspectedAt).ToList();
    }

    public async Task<Inspection?> GetInspectionAsync(string inspectionId)
    {
        return await _storage.GetItemAsync<Inspection>($"{InspectionsKeyPrefix}{inspectionId}");
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        await _storage.SetItemAsync($"{InspectionsKeyPrefix}{inspection.Id}", inspection);
        var ids = await GetAllInspectionIdsAsync();
        if (!ids.Contains(inspection.Id))
        {
            ids.Add(inspection.Id);
            await _storage.SetItemAsync(AllInspectionIdsKey, ids);
        }
    }

    public async Task DeleteInspectionAsync(string inspectionId)
    {
        await _storage.RemoveItemAsync($"{InspectionsKeyPrefix}{inspectionId}");
        var ids = await GetAllInspectionIdsAsync();
        ids.Remove(inspectionId);
        await _storage.SetItemAsync(AllInspectionIdsKey, ids);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var ids = await GetAllInspectionIdsAsync();
        var unsynced = new List<Inspection>();
        foreach (var id in ids)
        {
            var inspection = await GetInspectionAsync(id);
            if (inspection is { IsSynced: false, Status: InspectionStatus.Completed })
                unsynced.Add(inspection);
        }
        return unsynced;
    }

    public async Task MarkAsSyncedAsync(string inspectionId)
    {
        var inspection = await GetInspectionAsync(inspectionId);
        if (inspection != null)
        {
            inspection.IsSynced = true;
            await SaveInspectionAsync(inspection);
        }
    }

    private async Task<List<string>> GetAllInspectionIdsAsync()
    {
        return await _storage.GetItemAsync<List<string>>(AllInspectionIdsKey) ?? new List<string>();
    }
}

using System.Net.Http.Json;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly IInspectionStore _store;
    private readonly HttpClient _http;
    private Timer? _timer;
    private bool _isSyncing;

    public event Action<SyncStatus>? OnSyncStatusChanged;
    public SyncStatus CurrentStatus { get; private set; } = SyncStatus.Idle;
    public int PendingCount { get; private set; }

    public SyncService(IInspectionStore store, HttpClient http)
    {
        _store = store;
        _http = http;
    }

    public void StartPeriodicSync(TimeSpan interval)
    {
        _timer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.Zero, interval);
    }

    public async Task TrySyncAsync()
    {
        if (_isSyncing) return;
        _isSyncing = true;

        try
        {
            var unsynced = await _store.GetUnsyncedInspectionsAsync();
            PendingCount = unsynced.Count;

            if (unsynced.Count == 0)
            {
                UpdateStatus(SyncStatus.Idle);
                return;
            }

            UpdateStatus(SyncStatus.Syncing);

            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _store.MarkAsSyncedAsync(inspection.Id);
                        PendingCount--;
                    }
                }
                catch (HttpRequestException)
                {
                    // No connectivity — will retry next cycle
                    UpdateStatus(SyncStatus.Offline);
                    return;
                }
            }

            UpdateStatus(PendingCount > 0 ? SyncStatus.Error : SyncStatus.Synced);
        }
        catch
        {
            UpdateStatus(SyncStatus.Offline);
        }
        finally
        {
            _isSyncing = false;
        }
    }

    public async Task<int> GetPendingCountAsync()
    {
        var unsynced = await _store.GetUnsyncedInspectionsAsync();
        PendingCount = unsynced.Count;
        return PendingCount;
    }

    private void UpdateStatus(SyncStatus status)
    {
        CurrentStatus = status;
        OnSyncStatusChanged?.Invoke(status);
    }

    public void Dispose()
    {
        _timer?.Dispose();
    }
}

public enum SyncStatus
{
    Idle,
    Syncing,
    Synced,
    Offline,
    Error
}

using Microsoft.JSInterop;

namespace SiteInspector.Services;

public class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _dotNetRef;

    public bool IsOnline { get; private set; } = true;
    public event Action<bool>? OnConnectivityChanged;

    public ConnectivityService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        IsOnline = await _js.InvokeAsync<bool>("navigator.onLine.valueOf");
        await _js.InvokeVoidAsync("eval", $@"
            window.addEventListener('online', () => DotNet.invokeMethodAsync('SiteInspector', 'OnConnectivityChange', true));
            window.addEventListener('offline', () => DotNet.invokeMethodAsync('SiteInspector', 'OnConnectivityChange', false));
        ");
    }

    [JSInvokable("OnConnectivityChange")]
    public static void OnConnectivityChange(bool isOnline)
    {
        _staticInstance?.SetConnectivity(isOnline);
    }

    private static ConnectivityService? _staticInstance;

    public void RegisterStatic()
    {
        _staticInstance = this;
    }

    private void SetConnectivity(bool isOnline)
    {
        IsOnline = isOnline;
        OnConnectivityChanged?.Invoke(isOnline);
    }

    public async ValueTask DisposeAsync()
    {
        _dotNetRef?.Dispose();
    }
}

