@inherits LayoutComponentBase
@inject ConnectivityService Connectivity
@inject SyncService Sync

<div class="app-container">
    <header class="app-header">
        <a href="/" class="header-title">
            <span class="header-icon">🏗️</span>
            <span>Site Inspector</span>
        </a>
        <div class="sync-indicator @GetSyncClass()">
            @GetSyncIcon()
            @if (Sync.PendingCount > 0)
            {
                <span class="pending-badge">@Sync.PendingCount</span>
            }
        </div>
    </header>

    <main class="app-main">
        @Body
    </main>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        try
        {
            await Connectivity.InitializeAsync();
        }
        catch { /* JS interop may fail during prerender */ }

        Connectivity.OnConnectivityChanged += OnConnectivityChanged;
        Sync.OnSyncStatusChanged += OnSyncStatusChanged;
        Sync.StartPeriodicSync(TimeSpan.FromSeconds(30));
    }

    private void OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
            _ = Sync.TrySyncAsync();
        InvokeAsync(StateHasChanged);
    }

    private void OnSyncStatusChanged(SyncStatus status)
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetSyncClass() => Sync.CurrentStatus switch
    {
        SyncStatus.Syncing => "syncing",
        SyncStatus.Synced => "synced",
        SyncStatus.Offline => "offline",
        SyncStatus.Error => "error",
        _ => ""
    };

    private string GetSyncIcon() => Sync.CurrentStatus switch
    {
        SyncStatus.Syncing => "⟳",
        SyncStatus.Synced => "✓",
        SyncStatus.Offline => "⚡",
        SyncStatus.Error => "⚠",
        _ => Connectivity.IsOnline ? "☁️" : "⚡"
    };
}

@page "/"
@inject IInspectionStore Store
@inject NavigationManager Nav

<PageTitle>Sites - Site Inspector</PageTitle>

<div class="page-content">
    <div class="page-header">
        <h1>Construction Sites</h1>
        <button class="btn btn-primary" @onclick="ShowAddSite">+ Add Site</button>
    </div>

    @if (_showAddForm)
    {
        <div class="card add-form">
            <input class="input" @bind="_newSiteName" @bind:event="oninput" placeholder="Site name" />
            <input class="input" @bind="_newSiteAddress" @bind:event="oninput" placeholder="Address" />
            <div class="form-actions">
                <button class="btn btn-primary" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">Save</button>
                <button class="btn btn-secondary" @onclick="() => _showAddForm = false">Cancel</button>
            </div>
        </div>
    }

    @if (_sites.Count == 0 && !_showAddForm)
    {
        <div class="empty-state">
            <span class="empty-icon">🏗️</span>
            <p>No sites yet. Add your first construction site to begin inspections.</p>
        </div>
    }

    <div class="site-list">
        @foreach (var site in _sites)
        {
            <div class="card site-card" @onclick="() => Nav.NavigateTo($&quot;/site/{site.Id}&quot;)">
                <div class="site-info">
                    <h3>@site.Name</h3>
                    <p class="site-address">@site.Address</p>
                </div>
                <span class="chevron">›</span>
            </div>
        }
    </div>
</div>

@code {
    private List<Site> _sites = new();
    private bool _showAddForm;
    private string _newSiteName = "";
    private string _newSiteAddress = "";

    protected override async Task OnInitializedAsync()
    {
        _sites = await Store.GetSitesAsync();
    }

    private void ShowAddSite()
    {
        _showAddForm = true;
        _newSiteName = "";
        _newSiteAddress = "";
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;

        var site = new Site
        {
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim()
        };

        await Store.SaveSiteAsync(site);
        _sites = await Store.GetSitesAsync();
        _showAddForm = false;
    }
}

@page "/site/{SiteId}"
@inject IInspectionStore Store
@inject NavigationManager Nav

<PageTitle>Site Details - Site Inspector</PageTitle>

<div class="page-content">
    <div class="page-header">
        <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
        <h1>@_site?.Name</h1>
    </div>

    @if (_site != null)
    {
        <p class="site-address">@_site.Address</p>

        <button class="btn btn-primary btn-lg btn-full" @onclick="StartNewInspection">
            📋 New Inspection
        </button>

        <h2 class="section-title">Past Inspections</h2>

        @if (_inspections.Count == 0)
        {
            <div class="empty-state">
                <p>No inspections yet for this site.</p>
            </div>
        }

        <div class="inspection-list">
            @foreach (var inspection in _inspections)
            {
                <div class="card inspection-card" @onclick="() => Nav.NavigateTo($&quot;/inspection/{inspection.Id}&quot;)">
                    <div class="inspection-info">
                        <div class="inspection-date">@inspection.InspectedAt.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</div>
                        <div class="inspection-meta">
                            <span class="status-badge @inspection.Status.ToString().ToLower()">@inspection.Status</span>
                            @if (!inspection.IsSynced)
                            {
                                <span class="sync-badge">Not synced</span>
                            }
                            <span>@inspection.Checklist.Count(c => c.Result != CheckResult.NotChecked)/@inspection.Checklist.Count items</span>
                        </div>
                    </div>
                    <span class="chevron">›</span>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private Site? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        var sites = await Store.GetSitesAsync();
        _site = sites.FirstOrDefault(s => s.Id == SiteId);
        _inspections = await Store.GetInspectionsAsync(SiteId);
    }

    private void StartNewInspection()
    {
        Nav.NavigateTo($"/inspection/new/{SiteId}");
    }
}

