@inherits LayoutComponentBase
@inject ConnectivityService Connectivity
@inject SyncService Sync

<div class="app-container">
    <header class="app-header">
        <a href="/" class="header-title">
            <span class="header-icon">🏗️</span>
            <span>Site Inspector</span>
        </a>
        <div class="sync-indicator @GetSyncClass()">
            @GetSyncIcon()
            @if (Sync.PendingCount > 0)
            {
                <span class="pending-badge">@Sync.PendingCount</span>
            }
        </div>
    </header>

    <main class="app-main">
        @Body
    </main>
</div>

@code {
    protected override async Task OnInitializedAsync()
    {
        try
        {
            await Connectivity.InitializeAsync();
        }
        catch { /* JS interop may fail during prerender */ }

        Connectivity.OnConnectivityChanged += OnConnectivityChanged;
        Sync.OnSyncStatusChanged += OnSyncStatusChanged;
        Sync.StartPeriodicSync(TimeSpan.FromSeconds(30));
    }

    private void OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
            _ = Sync.TrySyncAsync();
        InvokeAsync(StateHasChanged);
    }

    private void OnSyncStatusChanged(SyncStatus status)
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetSyncClass() => Sync.CurrentStatus switch
    {
        SyncStatus.Syncing => "syncing",
        SyncStatus.Synced => "synced",
        SyncStatus.Offline => "offline",
        SyncStatus.Error => "error",
        _ => ""
    };

    private string GetSyncIcon() => Sync.CurrentStatus switch
    {
        SyncStatus.Syncing => "⟳",
        SyncStatus.Synced => "✓",
        SyncStatus.Offline => "⚡",
        SyncStatus.Error => "⚠",
        _ => Connectivity.IsOnline ? "☁️" : "⚡"
    };
}

