@page "/inspection/new/{SiteId}"
@page "/inspection/{InspectionId}"
@inject IInspectionStore Store
@inject NavigationManager Nav
@inject SyncService Sync

<PageTitle>Inspection - Site Inspector</PageTitle>

<div class="page-content inspection-page">
    <div class="page-header">
        <button class="btn-back" @onclick="GoBack">← Back</button>
        <h1>@(_isNew ? "New Inspection" : "Inspection")</h1>
    </div>

    @if (_inspection != null)
    {
        <div class="inspector-field">
            <input class="input" @bind="_inspection.InspectorName" @bind:event="oninput"
                   placeholder="Inspector name" @onfocusout="SaveDebounced" />
        </div>

        <!-- Category tabs for quick navigation -->
        <div class="category-tabs">
            @foreach (var category in _categories)
            {
                <button class="tab @(category == _activeCategory ? "active" : "")"
                        @onclick="() => SetCategory(category)">
                    @category
                    <span class="tab-count">@GetCategoryProgress(category)</span>
                </button>
            }
        </div>

        <!-- Checklist items for active category -->
        <div class="checklist">
            @foreach (var item in GetActiveItems())
            {
                <div class="checklist-item @item.Result.ToString().ToLower()">
                    <div class="item-header">
                        <span class="item-desc">@item.Description</span>
                    </div>
                    <div class="item-actions">
                        <button class="result-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                        <button class="result-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                        <button class="result-btn na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
                                @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                    </div>
                    @if (item.Result == CheckResult.Fail || !string.IsNullOrEmpty(item.Notes))
                    {
                        <textarea class="item-notes" @bind="item.Notes" @bind:event="oninput"
                                  @onfocusout="SaveDebounced"
                                  placeholder="Add notes (required for failures)..." rows="2"></textarea>
                    }
                </div>
            }
        </div>

        <!-- General Notes -->
        <div class="section">
            <h2 class="section-title">General Notes</h2>
            <textarea class="input notes-area" @bind="_inspection.Notes" @bind:event="oninput"
                      @onfocusout="SaveDebounced"
                      placeholder="Additional observations..." rows="4"></textarea>
        </div>

        <!-- Photos -->
        <div class="section">
            <h2 class="section-title">Photos (@_inspection.Photos.Count)</h2>
            <PhotoCapture Photos="_inspection.Photos" OnPhotoAdded="SaveDebounced" />
        </div>

        <!-- Actions -->
        <div class="form-actions sticky-actions">
            @if (_inspection.Status == InspectionStatus.InProgress)
            {
                <button class="btn btn-primary btn-lg" @onclick="CompleteInspection"
                        disabled="@(!CanComplete())">
                    ✓ Complete Inspection
                </button>
            }
            else
            {
                <div class="completed-banner">
                    ✓ Inspection Completed
                    @if (!_inspection.IsSynced)
                    {
                        <span class="sync-badge">Pending sync</span>
                    }
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string? SiteId { get; set; }
    [Parameter] public string? InspectionId { get; set; }

    private Inspection? _inspection;
    private bool _isNew;
    private List<string> _categories = new();
    private string _activeCategory = "";
    private Timer? _saveTimer;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrEmpty(InspectionId) && InspectionId != "new")
        {
            _inspection = await Store.GetInspectionAsync(InspectionId);
            _isNew = false;
        }
        else if (!string.IsNullOrEmpty(SiteId))
        {
            _inspection = new Inspection
            {
                SiteId = SiteId,
                Checklist = ChecklistTemplates.GetStandardChecklist()
            };
            _isNew = true;
            await Store.SaveInspectionAsync(_inspection);
        }

        if (_inspection != null)
        {
            _categories = _inspection.Checklist.Select(c => c.Category).Distinct().ToList();
            _activeCategory = _categories.FirstOrDefault() ?? "";
        }
    }

    private void SetCategory(string category)
    {
        _activeCategory = category;
    }

    private List<ChecklistItem> GetActiveItems()
    {
        return _inspection?.Checklist.Where(c => c.Category == _activeCategory).ToList() ?? new();
    }

    private string GetCategoryProgress(string category)
    {
        var items = _inspection?.Checklist.Where(c => c.Category == category).ToList();
        if (items == null) return "";
        var done = items.Count(i => i.Result != CheckResult.NotChecked);
        return $"{done}/{items.Count}";
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = result;
        await SaveAsync();
    }

    private async void SaveDebounced()
    {
        _saveTimer?.Dispose();
        _saveTimer = new Timer(async _ =>
        {
            await SaveAsync();
        }, null, 500, Timeout.Infinite);
    }

    private async Task SaveAsync()
    {
        if (_inspection != null)
        {
            await Store.SaveInspectionAsync(_inspection);
        }
    }

    private bool CanComplete()
    {
        if (_inspection == null) return false;
        var failures = _inspection.Checklist.Where(c => c.Result == CheckResult.Fail);
        return !failures.Any(f => string.IsNullOrWhiteSpace(f.Notes));
    }

    private async Task CompleteInspection()
    {
        if (_inspection == null) return;
        _inspection.Status = InspectionStatus.Completed;
        await Store.SaveInspectionAsync(_inspection);
        _ = Sync.TrySyncAsync();
    }

    private void GoBack()
    {
        if (!string.IsNullOrEmpty(_inspection?.SiteId))
            Nav.NavigateTo($"/site/{_inspection.SiteId}");
        else
            Nav.NavigateTo("/");
    }
}

@inject IJSRuntime JS

<div class="photo-section">
    <label class="btn btn-secondary photo-btn">
        📷 Add Photo
        <InputFile OnChange="HandleFileSelected" accept="image/*" capture="environment" style="display:none" />
    </label>

    @if (Photos.Count > 0)
    {
        <div class="photo-grid">
            @foreach (var photo in Photos)
            {
                <div class="photo-item">
                    <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.Caption" />
                    <input class="photo-caption" @bind="photo.Caption" @bind:event="oninput"
                           placeholder="Caption..." @onfocusout="NotifyChanged" />
                    <button class="photo-remove" @onclick="() => RemovePhoto(photo)">×</button>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public List<PhotoAttachment> Photos { get; set; } = new();
    [Parameter] public EventCallback OnPhotoAdded { get; set; }

    private async Task HandleFileSelected(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file == null) return;

        // Resize for mobile - max 1024px wide to save storage
        var resized = await file.RequestImageFileAsync("image/jpeg", 1024, 1024);
        using var stream = resized.OpenReadStream(maxAllowedSize: 5 * 1024 * 1024);
        using var ms = new MemoryStream();
        await stream.CopyToAsync(ms);

        var photo = new PhotoAttachment
        {
            FileName = file.Name,
            Base64Data = Convert.ToBase64String(ms.ToArray()),
            TakenAt = DateTime.UtcNow
        };

        Photos.Add(photo);
        await OnPhotoAdded.InvokeAsync();
    }

    private async Task RemovePhoto(PhotoAttachment photo)
    {
        Photos.Remove(photo);
        await OnPhotoAdded.InvokeAsync();
    }

    private async Task NotifyChanged()
    {
        await OnPhotoAdded.InvokeAsync();
    }
}

