    font-size: 1rem;
    margin-bottom: 0.75rem;
    outline: none;
    transition: border-color 0.2s;
}
.input:focus { border-color: var(--primary); }

.form-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 0.5rem;
}

.add-form {
    padding: 1.25rem;
}

