.btn-lg { padding: 0.9rem 1.5rem; font-size: 1.05rem; }
.btn-full { width: 100%; margin: 1rem 0; }

.btn-back {
    background: none;
    border: none;
    color: var(--primary);
    font-size: 1rem;
    font-weight: 500;
    padding: 0.3rem 0;
    cursor: pointer;
    touch-action: manipulation;
}

/* Cards */
.card {
    background: white;
    border-radius: var(--radius);
    padding: 1rem;
    margin-bottom: 0.75rem;
    box-shadow: var(--shadow);
    transition: transform 0.1s;
}
.card:active { transform: scale(0.98); }

.site-card, .inspection-card {
    display: flex;
    align-items: center;
    cursor: pointer;
}
.site-info, .inspection-info { flex: 1; }
.site-info h3 { margin: 0 0 0.2rem; font-size: 1.05rem; }
.site-address { color: var(--gray-500); font-size: 0.85rem; margin: 0; }
.chevron { color: var(--gray-300); font-size: 1.5rem; font-weight: 300; }

.inspection-date { font-weight: 500; margin-bottom: 0.25rem; }
.inspection-meta {
    display: flex;
    gap: 0.5rem;
    align-items: center;
    font-size: 0.8rem;
    color: var(--gray-500);
}

.status-badge {
    padding: 0.1rem 0.5rem;
    border-radius: 10px;
    font-size: 0.7rem;
    font-weight: 600;
    text-transform: uppercase;
}
.status-badge.inprogress { background: #fef3c7; color: #92400e; }
.status-badge.completed { background: #d1fae5; color: #065f46; }
.sync-badge {
    background: #fee2e2;
    color: #991b1b;
    padding: 0.1rem 0.5rem;
    border-radius: 10px;
    font-size: 0.7rem;
    font-weight: 600;
}

/* Forms */
.input {
    width: 100%;
    padding: 0.75rem 1rem;
    border: 1.5px solid var(--gray-200);
    border-radius: var(--radius);
    font-size: 1rem;
    margin-bottom: 0.75rem;
    outline: none;
    transition: border-color 0.2s;
}
.input:focus { border-color: var(--primary); }

.form-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 0.5rem;
}

.add-form {
    padding: 1.25rem;
}

/* Empty state */
.empty-state {
    text-align: center;
    padding: 3rem 1rem;
    color: var(--gray-500);
}
.empty-icon { font-size: 3rem; display: block; margin-bottom: 1rem; }

/* Section */
.section { margin-top: 1.5rem; }
.section-title {
    font-size: 1rem;
    font-weight: 600;
    color: var(--gray-700);
    margin: 0 0 0.75rem;
}

/* Category tabs - horizontal scrollable */
.category-tabs {
    display: flex;
    gap: 0.5rem;
    overflow-x: auto;
    padding: 0.5rem 0;
    margin-bottom: 1rem;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: none;
}
.category-tabs::-webkit-scrollbar { display: none; }

.tab {
    flex-shrink: 0;
    padding: 0.5rem 0.9rem;
    border: 1.5px solid var(--gray-200);
    border-radius: 20px;
    background: white;
    font-size: 0.8rem;
    font-weight: 500;
    cursor: pointer;
    touch-action: manipulation;
    transition: all 0.15s;
}
.tab.active {
    background: var(--primary);
    color: white;
    border-color: var(--primary);
}
.tab-count {
    margin-left: 0.3rem;
    opacity: 0.7;
    font-size: 0.75rem;
}

/* Checklist */
.checklist {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.checklist-item {
    background: white;
    border-radius: var(--radius);
    padding: 0.75rem 1rem;
    box-shadow: var(--shadow);
    border-left: 4px solid var(--gray-200);
    transition: border-color 0.2s;
}
.checklist-item.pass { border-left-color: var(--success); }
.checklist-item.fail { border-left-color: var(--danger); }
.checklist-item.notapplicable { border-left-color: var(--gray-300); }

.item-header {
    margin-bottom: 0.5rem;
}
.item-desc {
    font-size: 0.9rem;
    font-weight: 500;
}

.item-actions {
    display: flex;
    gap: 0.5rem;
}

.result-btn {
    flex: 1;
    padding: 0.6rem;
    border: 2px solid var(--gray-200);
    border-radius: 8px;
    background: white;
    font-size: 1.1rem;
    font-weight: 700;
    cursor: pointer;
    touch-action: manipulation;
    transition: all 0.1s;
}
.result-btn:active { transform: scale(0.95); }
.result-btn.pass.selected { background: #d1fae5; border-color: var(--success); color: var(--success); }
.result-btn.fail.selected { background: #fee2e2; border-color: var(--danger); color: var(--danger); }
.result-btn.na.selected { background: var(--gray-100); border-color: var(--gray-500); color: var(--gray-500); }

.item-notes {
    width: 100%;
    margin-top: 0.5rem;
    padding: 0.5rem 0.75rem;
    border: 1.5px solid var(--gray-200);
    border-radius: 8px;
    font-size: 0.85rem;
    resize: none;
    outline: none;
}
.item-notes:focus { border-color: var(--primary); }

/* Notes */
.notes-area { resize: vertical; min-height: 80px; }

/* Inspector field */
.inspector-field { margin-bottom: 1rem; }

/* Photos */
.photo-section { margin-top: 0.5rem; }
.photo-btn { width: 100%; margin-bottom: 1rem; }

.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
    gap: 0.75rem;
}

.photo-item {
    position: relative;
    border-radius: var(--radius);
    overflow: hidden;
    box-shadow: var(--shadow);
    background: white;
}
.photo-item img {
    width: 100%;
    height: 120px;
    object-fit: cover;
    display: block;
}
.photo-caption {
    width: 100%;
    padding: 0.4rem 0.5rem;
    border: none;
    font-size: 0.75rem;
    outline: none;
    background: white;
}
.photo-remove {
    position: absolute;
    top: 4px;
    right: 4px;
    width: 24px;
    height: 24px;
    border-radius: 50%;
    border: none;
    background: rgba(0,0,0,0.6);
    color: white;
    font-size: 1rem;
    line-height: 1;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
}

/* Sticky actions */
.sticky-actions {
    position: sticky;
    bottom: 0;
    padding: 1rem 0;
    background: var(--gray-50);
    margin-top: 2rem;
}

.completed-banner {
    text-align: center;
    padding: 1rem;
    background: #d1fae5;
    color: #065f46;
    border-radius: var(--radius);
    font-weight: 600;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0.75rem;
}

/* Error UI */
#blazor-error-ui {
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}
#blazor-error-ui .dismiss {
    cursor: pointer;
    position: absolute;
    right: 0.75rem;
    top: 0.5rem;
}
EOF

